  ('dietitian-moex-10464', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '1999-2000年台灣地區老人營養健康狀況調查中，對老人維生素B 生化營養狀況的評估方法是藉由測定紅血球 1 轉酮 活性係數（erythrocyte transketolase activity coefficient, ETKAC）來判斷，請問判定為缺乏之標準為何？ ETKAC<1.12  ETKAC<1.15  1.15<ETKAC<1.20  ETKAC≥1.20', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10465', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不是近年台灣地區國民營養健康變遷調查用來判定國人缺鐵盛行率的指標之一？ 血紅素  鐵儲存量  運鐵蛋白飽和度  血清鐵蛋白', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10466', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '目前歐美各國常用何種體位測量方法作為判定兒童肥胖之指標？ 年齡別體重（weight-for-age）  身高別體重（weight-for-height） 年齡別身體質量指數（BMI-for-age）  重高指數（weight-for-length index）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10467', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在探討飲食因子與疾病相關性的流行病學研究中，下列何種流行病學指標較為適用？ 死亡率  出生率  盛行率  發生率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10468', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者是郵寄問卷調查的優點？ 回收率高  成本低廉  不易代答  容易具有代表性', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10469', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '為降低國人癌症的發生率，衛生機關對一般民眾廣為宣導「天天五蔬果」，期望國人能提高蔬果的攝取量 ，預防癌症的發生。請問此種預防方式屬於那一級的預防？ 第四級預防  第三級預防  第二級預防  第一級預防', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10470', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某研究者想深入瞭解民眾使用健康食品的動機時，發現他在此方面的知識不足，無法提供完整的問題答案 選項，請問此時的問卷適合何種類型的題目？ 結構型題目  封閉型題目  開放式題目  表格式題目', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10471', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '行政院衛生署於民國九十二年將每日營養素建議攝取量（recommended daily nutrients allowances, RDNA）更 改為膳食營養素參考攝取量（dietary reference intakes, DRIs），主要是根據最近營養的研究結果，依各個營 養素的特性，由單獨的RDNA，增加另外三種建議量，除平均需要量（estimated average requirement, EAR） 及足夠攝取量（adequate intake, AI）外，尚包括那一種建議量？ 上限攝取量（tolerable upper intake level, UL）  每日攝取量（daily intake, DI） 最低攝取量（minimum intake, MI）  參考攝取量（reference intake, RI）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10472', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '行政院衛生署所訂每日飲食指南所呈現的圖形為： 金字塔  寶塔  梅花  圓形', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10473', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '梁小姐的飲食紀錄顯示，她每天約攝取60公克蛋白質、60公克脂肪及220公克醣類。請問她由醣類所提供 的熱量較我國飲食指標所訂醣類提供熱量百分比之建議下限： 低10%  低8%  低5%  低3%', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
